def initialize(collection)
      raise NotSupportedError, "#{collection.inspect} does not support :async_count" unless collection.respond_to?(:async_count)

      @collection = collection.except(:select, :order)
      @promise = @collection.async_count
    end

def respond_to_on_destroy(non_navigational_status: :no_content)
    # We actually need to hardcode this as Rails default responder doesn't
    # support returning empty response on GET request
    respond_to do |format|
      format.all { head non_navigational_status }
      format.any(*navigational_formats) { redirect_to after_sign_out_path_for(resource_name), status: Devise.responder.redirect_status }
    end
  end

def initialize(app, routes_app = nil, response_format = :default, interceptors = self.class.interceptors)
      @app             = app
      @routes_app      = routes_app
      @response_format = response_format
      @interceptors    = interceptors
    end

def respond_to_missing?(name, include_private = false)
        if self.class.define_attribute_methods
          # Some methods weren't defined yet.
          return true if self.class.method_defined?(name)
          return true if include_private && self.class.private_method_defined?(name)
        end

        super
      end

def matches?(name, payload, tags)
            return false unless name.to_s == event_data[:name]

            if payload && payload.is_a?(Hash)
              return false unless matches_hash?(payload, :payload)
            end

            return false unless matches_hash?(tags, :tags)
            true
          end
